#include <map>
#include <string>
#include <fstream>
#include <sstream>
    std::map<std::string, std::string> dict;
    std::ifstream file("dictionary.tsv");
    std::string line;
    while (std::getline(file, line)) {
        size_t tab = line.find('\t');
        if (tab != std::string::npos) {
            dict[line.substr(0, tab)] = line.substr(tab + 1);
        }
    }
